const ACHIEVEMENT_DEFS: Omit<Achievement, "unlocked" | "unlockedAt">[] = [
  { id: "first_putt", name: "First Swing", description: "Complete your first putt", icon: "🏌️" },
  { id: "hole_in_one", name: "Ace!", description: "Score a hole-in-one", icon: "⭐" },
